import React from 'react';
import "./Menu.css";
import "nes.css/css/nes.min.css";


let displayMenu = false;

const openMenu = () => {
	displayMenu = true;
}

const Menu = (displayMenu) => {
	if (displayMenu) {
    return <label>
						<a onClick={this.openMenu}>
							<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
							<span>Start</span>
						</a>
					</label>
	} else {
			return (
				<div class="nes-container is-dark with-title">
  				<p class="title">OPTIONS</p>
  				<a onClick="">
					<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
					<span>Character</span>
				</a>
				<a onClick="">
					<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
						<span>Projects</span>
					</a>
					<a onClick="">
						<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
						<span>Contact</span>
					</a>
				</div>
			)
	}
}

export default Menu;
